public int networkDelayTime(int[][] times, int n, int k) {
    Map<Integer, List<int[]>> graph = new HashMap<>();
    for (int[] t : times) graph.computeIfAbsent(t[0], x -> new ArrayList<>()).add(new int[]{t[1], t[2]});
    int[] dist = new int[n + 1];
    Arrays.fill(dist, Integer.MAX_VALUE);
    dist[k] = 0;
    PriorityQueue<int[]> heap = new PriorityQueue<>((a, b) -> a[0] - b[0]);
    heap.offer(new int[]{0, k});
    while (!heap.isEmpty()) {
        int[] cur = heap.poll();
        int d = cur[0], node = cur[1];
        if (d > dist[node]) continue;
        for (int[] edge : graph.getOrDefault(node, new ArrayList<>())) {
            int nd = d + edge[1];
            if (nd < dist[edge[0]]) {
                dist[edge[0]] = nd;
                heap.offer(new int[]{nd, edge[0]});
            }
        }
    }
    int result = 0;
    for (int i = 1; i <= n; i++) result = Math.max(result, dist[i]);
    return result == Integer.MAX_VALUE ? -1 : result;
}

