function findWords(board: string[][], words: string[]): string[] {
  const root: any = {};
  for (const word of words) {
    let node = root;
    for (const c of word) node = node[c] = node[c] || {};
    node['#'] = word;
  }
  const rows = board.length, cols = board[0].length;
  const result: string[] = [];
  function dfs(r: number, c: number, node: any) {
    const char = board[r][c];
    if (!(char in node)) return;
    const nxt = node[char];
    if ('#' in nxt) {
      result.push(nxt['#']);
      delete nxt['#'];
    }
    board[r][c] = '*';
    for (const [dr, dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
      const nr = r + dr, nc = c + dc;
      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && board[nr][nc] !== '*') dfs(nr, nc, nxt);
    }
    board[r][c] = char;
  }
  for (let r = 0; r < rows; r++) for (let c = 0; c < cols; c++) dfs(r, c, root);
  return result;
}

