type WDNode struct {
    children map[byte]*WDNode
    isEnd    bool
}
type WordDictionary struct {
    root *WDNode
}
func Constructor() WordDictionary {
    return WordDictionary{root: &WDNode{children: make(map[byte]*WDNode)}}
}
func (d *WordDictionary) AddWord(word string) {
    node := d.root
    for i := 0; i < len(word); i++ {
        c := word[i]
        if node.children[c] == nil {
            node.children[c] = &WDNode{children: make(map[byte]*WDNode)}
        }
        node = node.children[c]
    }
    node.isEnd = true
}
func (d *WordDictionary) Search(word string) bool {
    var dfs func(node *WDNode, i int) bool
    dfs = func(node *WDNode, i int) bool {
        if i == len(word) { return node.isEnd }
        c := word[i]
        if c == '.' {
            for _, child := range node.children {
                if dfs(child, i+1) { return true }
            }
            return false
        }
        if node.children[c] == nil { return false }
        return dfs(node.children[c], i+1)
    }
    return dfs(d.root, 0)
}

