function alienOrder(words: string[]): string {
  const graph = new Map<string, Set<string>>();
  const inDegree = new Map<string, number>();
  for (const w of words) for (const c of w) inDegree.set(c, 0);
  for (let i = 0; i < words.length - 1; i++) {
    const w1 = words[i], w2 = words[i + 1];
    const minLen = Math.min(w1.length, w2.length);
    if (w1.length > w2.length && w1.slice(0, minLen) === w2.slice(0, minLen)) return '';
    for (let j = 0; j < minLen; j++) {
      if (w1[j] !== w2[j]) {
        if (!graph.has(w1[j])) graph.set(w1[j], new Set());
        if (!graph.get(w1[j])!.has(w2[j])) {
          graph.get(w1[j])!.add(w2[j]);
          inDegree.set(w2[j], (inDegree.get(w2[j]) || 0) + 1);
        }
        break;
      }
    }
  }
  const queue: string[] = [...inDegree.entries()].filter(([, d]) => d === 0).map(([c]) => c);
  let result = '';
  while (queue.length) {
    const c = queue.shift()!;
    result += c;
    for (const neighbor of graph.get(c) || []) {
      inDegree.set(neighbor, inDegree.get(neighbor)! - 1);
      if (inDegree.get(neighbor) === 0) queue.push(neighbor);
    }
  }
  return result.length === inDegree.size ? result : '';
}

