        for j := 0; j < minLen; j++ {
            if w1[j] != w2[j] {
                if graph[w1[j]] == nil { graph[w1[j]] = make(map[byte]bool) }
                if !graph[w1[j]][w2[j]] {
                    graph[w1[j]][w2[j]] = true
                    inDegree[w2[j]]++
                }
                break
