    for c, d := range inDegree {
        if d == 0 { queue = append(queue, c) }
    }
    result := []byte{}
    for len(queue) > 0 {
        c := queue[0]
        queue = queue[1:]
        result = append(result, c)
        for neighbor := range graph[c] {
            inDegree[neighbor]--
            if inDegree[neighbor] == 0 { queue = append(queue, neighbor) }
        }
    }
    if len(result) != len(inDegree) { return "" }
