func findCheapestPrice(n int, flights [][]int, src int, dst int, k int) int {
    prices := make([]int, n)
    for i := range prices { prices[i] = math.MaxInt32 }
    prices[src] = 0
    for i := 0; i <= k; i++ {
        temp := make([]int, n)
        copy(temp, prices)
        for _, f := range flights {
            u, v, w := f[0], f[1], f[2]
            if prices[u] != math.MaxInt32 && prices[u]+w < temp[v] {
                temp[v] = prices[u] + w
            }
        }
        prices = temp
    }
    if prices[dst] == math.MaxInt32 { return -1 }
    return prices[dst]
}

