    for (int round = 0; round < k; round++) {
        while (i < n && capital[indices[i]] <= w) {
            maxHeap.offer(profits[indices[i]]);
            i++;
        }
        if (maxHeap.isEmpty()) break;
        w += maxHeap.poll();
    }
    return w;
}

